/**
 * Cerca un vino nel database e restituisce tipo, regione e produttore.
 * Funziona sia per nome vino che per produttore/cantina.
 * @param {string} nome - Nome del vino o della cantina
 * @returns {{ tipo: string, regione: string, produttore: string, vino: string } | null}
 */
export function lookupWine(nome) {
  if (!nome || nome.length < 3) return null
  const n = nome.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ').trim()

  // 1. Match esatto
  if (WINES_DB[n]) return WINES_DB[n]

  // 2. Cerca per parole chiave nel nome
  const words = n.split(' ').filter(w => w.length >= 4)
  let best = null
  let bestScore = 0

  for (const [kw, data] of Object.entries(WINES_DB)) {
    let score = 0
    // Il nome contiene la keyword
    if (n.includes(kw)) score = kw.length * 2
    // La keyword contiene parte del nome
    else {
      for (const word of words) {
        if (kw.includes(word)) score += word.length
        else if (word.includes(kw) && kw.length >= 5) score += kw.length * 0.8
      }
    }
    if (score > bestScore) { bestScore = score; best = data }
  }

  // Soglia minima per evitare falsi positivi
  if (bestScore >= 6) return best
  return null
}
